INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Markdown-Native Editing$q$, $q$Write notes in Markdown with syntax highlighting, tables and LaTeX math support built directly into the editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Self-Hosted Deployment$q$, $q$Runs as a single Go binary or ~20MB Docker image on a Raspberry Pi, VPS or cloud server, with SQLite, MySQL or PostgreSQL as the data store.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Full-Text Search and Tagging$q$, $q$A flexible tag system combined with full-text search makes it fast to organize and retrieve past notes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Media Attachments$q$, $q$Drag-and-drop support for images, video, audio and documents directly into any memo.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Selective Public Sharing$q$, $q$Share individual memos publicly via a simple link while keeping the rest of the notebook private.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Data Portability$q$, $q$Export all notes to Markdown, JSON or CSV at any time, avoiding lock-in to a proprietary format.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$REST and gRPC APIs$q$, $q$Open APIs allow developers to build custom clients, browser extensions and third-party integrations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Zero Telemetry$q$, $q$No usage tracking or analytics are sent to any third party, since the entire application runs on infrastructure the user controls.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Full data ownership through self-hosting, with no vendor lock-in$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Lightweight and fast, with a small resource footprint suitable for a Raspberry Pi$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Simple, quick-capture timeline interface that is faster than heavier note apps for short-form notes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Active open-source community contributing translations, themes and integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Requires technical comfort with Docker or server administration to self-host$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$No official managed cloud hosting, so users are responsible for backups and uptime$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Timeline-based structure is less suited to long-form documents or deeply nested wikis$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Fewer built-in collaboration features than commercial team note tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$No official enterprise support contract or SLA since it is a community project$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Is Memos free to use?$q$, $q$Yes, Memos is completely free and open source under the MIT license, with no subscription fees or paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Do I need to self-host Memos?$q$, $q$Yes, Memos does not offer an official managed cloud version, so users deploy it themselves on a server, VPS, home device such as a Raspberry Pi, or a container platform such as Docker.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$What databases does Memos support?$q$, $q$Memos supports SQLite, MySQL and PostgreSQL as its storage backend, letting users choose based on the scale of their deployment.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Can I export my notes out of Memos?$q$, $q$Yes, Memos supports exporting notes to Markdown, JSON or CSV, so data always remains portable.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Does Memos support Markdown and attachments?$q$, $q$Yes, Memos is Markdown-native and supports syntax highlighting, tables, LaTeX math, and drag-and-drop images, video, audio and document attachments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Who maintains Memos?$q$, $q$Memos is maintained by the usememos open-source community on GitHub, led by its original developer, with contributions from a large community of volunteers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Personal Daily Journaling$q$, $q$Individuals use Memos as a quick-capture timeline for daily thoughts, to-dos and links, similar to a personal microblog.$q$, $q$Individuals and privacy-conscious note-takers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Self-Hosted Team Notes$q$, $q$Small technical teams deploy a shared Memos instance on internal infrastructure to jot down quick updates and shared references without adopting a paid SaaS tool.$q$, $q$Small development or IT teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Home Lab and Raspberry Pi Projects$q$, $q$Hobbyists running home labs use Memos as a lightweight self-hosted app alongside other services, since it requires minimal resources.$q$, $q$Self-hosting and home-lab enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT-licensed source code","Unlimited notes and users","SQLite, MySQL or PostgreSQL storage","REST and gRPC APIs","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Memos is a free, open-source note-taking application designed for people who want full control over their notes without relying on a cloud subscription service. Instead of a traditional folder-and-document structure, Memos presents notes as a reverse-chronological timeline, similar to a personal microblog, making it well suited to capturing short-form thoughts, links, and daily logs quickly.$q$, $q$The project is self-hosted, meaning users run their own instance on a server, VPS, home lab device such as a Raspberry Pi, or a cloud container platform. Because the entire codebase is MIT-licensed and available on GitHub, anyone can inspect, modify or extend it, and there is no dependency on an external company staying in business to keep the notes accessible.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Memos supports Markdown formatting with syntax highlighting, tables and LaTeX math, along with drag-and-drop attachments for images, video, audio and documents. A flexible tagging system and full-text search make it easy to retrieve older notes, while public sharing links let users publish individual memos without exposing their entire notebook.$q$, $q$Technically, Memos ships as a single Go binary and a compact Docker image, supports SQLite, MySQL or PostgreSQL as the storage backend, and exposes REST and gRPC APIs for building custom integrations. The interface is a progressive web app with offline support and a dark mode, and all data can be exported to Markdown, JSON or CSV at any time.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Memos itself carries no license fee: the software is entirely free and open source under the MIT license, with no paid tiers, subscriptions or per-user charges built into the product.$q$, $q$The only cost users incur is whatever infrastructure they choose to run it on, such as a small VPS, a home server, or a container hosting platform, which for a lightweight single-Go-binary app is typically inexpensive.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4d5b94dc-fbd1-4f00-aeaf-079f4a300745', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Software Composition Analysis$q$, $q$Builds a real-time inventory of open-source dependencies and flags known CVEs and license-compliance risks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Automated Remediation$q$, $q$Generates pull requests that automatically update vulnerable dependencies to patched versions rather than only reporting them.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Static Application Security Testing$q$, $q$Scans proprietary, first-party code for security vulnerabilities alongside open-source dependency risk.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Renovate Dependency Automation$q$, $q$Mend stewards the popular open-source Renovate bot, offering an enterprise edition for automated, policy-driven dependency updates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Mend AI$q$, $q$Extends inventory and risk scanning to AI models and machine-learning components used inside applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Reachability Analysis$q$, $q$Prioritizes vulnerabilities based on whether the vulnerable code path is actually reachable and exploitable, reducing alert noise.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$License Compliance Tracking$q$, $q$Flags open-source license risks alongside security vulnerabilities to support legal and compliance review.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$CI/CD and SCM Integrations$q$, $q$Integrates with GitHub, GitLab, Bitbucket and major CI/CD pipelines to scan code as part of the existing development workflow.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Strong automated remediation that generates fix pull requests rather than just alerts$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Broad platform covering SCA, SAST, container and AI component security in one product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Deep dependency-update integration through its stewardship of the open-source Renovate bot$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Established vendor with over a decade of experience in the software composition analysis category$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Reachability-based prioritization helps reduce false-positive alert fatigue$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Pricing is not published and requires a sales conversation for every deal$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Per-developer pricing can become expensive for large engineering organizations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Some users report a learning curve configuring policies across a large monorepo estate$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Primarily targeted at enterprise buyers, with less self-serve accessibility for small teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Overlapping product lines from acquisitions can add platform complexity$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$What was Mend.io previously called?$q$, $q$Mend.io was known as WhiteSource Software until it rebranded in May 2022 to reflect its expanded focus on automated remediation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$What does Mend.io do?$q$, $q$Mend.io provides software composition analysis, static application security testing and automated remediation to help organizations secure open-source and custom application code.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$How is Mend.io priced?$q$, $q$Pricing is quoted per contributing developer per year and is not published publicly; buyers need to contact sales for a quote, though free trials are available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Where is Mend.io headquartered?$q$, $q$Mend.io is headquartered in Tel Aviv-Yafo, Israel, with a significant office presence in Boston, Massachusetts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Does Mend.io offer a free trial?$q$, $q$Yes, Mend.io offers free trials and proof-of-concept access on request, though it does not have a permanent free tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$What is Mend Renovate?$q$, $q$Mend Renovate is an automated dependency-update tool, built on the open-source Renovate bot that Mend stewards, available in a free open-source form and a paid Enterprise edition.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Enterprise Open-Source Risk Management$q$, $q$Large engineering organizations use Mend to maintain a real-time inventory of open-source dependencies and automatically remediate known vulnerabilities across hundreds of repositories.$q$, $q$Enterprise security and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Regulatory and License Compliance$q$, $q$Legal and compliance teams use Mend's license-tracking features to ensure open-source usage complies with company policy and software supply-chain regulations.$q$, $q$Compliance and legal teams at software companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Automated Dependency Updates$q$, $q$Development teams use Mend Renovate to automatically open pull requests that keep dependencies patched and up to date without manual tracking.$q$, $q$Software development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Mend Renovate Enterprise$q$, $q$From approximately $250/contributing developer$q$, $q$Annual$q$, NULL, $q$["Automated dependency updates","Policy-driven update rules","Enterprise support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Mend AI Premium$q$, $q$From approximately $300/contributing developer$q$, $q$Annual$q$, NULL, $q$["AI and ML component inventory","Model risk scanning"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$Mend AppSec$q$, $q$From approximately $1,000/contributing developer$q$, $q$Annual$q$, NULL, $q$["Software composition analysis","Static application security testing","Renovate dependency automation","AI component inventory"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mend.io is an application security company that helps organizations find, prioritize and automatically fix vulnerabilities in the open-source components and custom code that make up modern software. Formerly known as WhiteSource, the company rebranded in 2022 to reflect a broader platform that goes beyond inventory and license tracking into automated remediation.$q$, $q$The platform is aimed at engineering and security teams inside mid-market and enterprise organizations that need to manage open-source risk at scale, satisfy compliance frameworks, and reduce the manual burden of patching vulnerable dependencies across large codebases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mend's core capability is software composition analysis (SCA): it scans a codebase's package manifests and lockfiles to build a real-time bill of materials, matches dependencies against known vulnerability databases, and flags license-compliance risks. Automated remediation pull requests can bump a flagged dependency directly to a patched version.$q$, $q$Beyond SCA, Mend offers static application security testing (SAST) for first-party code, container and cloud-native scanning, and Mend AI for inventorying and assessing risk in AI and machine-learning components. The company also stewards Renovate, a widely used open-source dependency-update bot, and offers an enterprise version with additional controls.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c102b52-3adb-4485-b65a-2b1065f9aa19', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mend.io does not publish transparent list pricing; costs are quoted per 'contributing developer' per year and negotiated through the sales team, with free trials or proof-of-concept access available on request.$q$, $q$Third-party sources report tiers ranging from roughly $250 per developer per year for Mend Renovate Enterprise up to around $1,000 per developer per year for the full Mend AppSec bundle that combines SCA, SAST, Renovate and AI component inventory.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Real-Time Social and Web Monitoring$q$, $q$Continuously tracks mentions across major social networks, news sites, blogs and forums as they happen.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Review Site Monitoring$q$, $q$Tracks mentions and ratings across more than 75 review platforms including Google, Trustpilot, Amazon and Glassdoor.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Boolean Search Alerts$q$, $q$Lets users build precise monitoring queries using AND, OR, NOT and wildcard operators to reduce irrelevant results.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Sentiment Analysis$q$, $q$Automatically classifies mentions as positive, negative or neutral to gauge brand perception over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Competitor Benchmarking$q$, $q$Compares share of voice and mention volume against named competitors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Influence Scoring$q$, $q$Ranks authors and sources by estimated reach and influence to help prioritize outreach.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$White-Label Reporting$q$, $q$Agencies can generate and export custom-branded reports for clients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Team Collaboration Tools$q$, $q$Multi-user access controls let marketing and PR teams share alerts, dashboards and reports.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Broad source coverage spanning social media, news, forums and dedicated review sites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Boolean search gives precise control over what counts as a relevant mention$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Agency-friendly white-label reporting and multi-client management$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Mid-market pricing that is more accessible than enterprise suites like Brandwatch or Meltwater$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Established track record, operating since the early 2010s with broad international coverage$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$No permanent free tier, only a time-limited free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Entry-level Solo plan is limited to a single user and very few alerts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Some integrations, such as Slack and Zapier, are gated behind paid add-ons$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Less deep historical and archival data access compared to enterprise-grade competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Sentiment analysis accuracy, like most automated tools, can struggle with sarcasm or industry-specific language$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$What does Mention do?$q$, $q$Mention is a social listening and media monitoring platform that tracks brand, competitor and keyword mentions across social media, news, blogs, forums and review sites in real time.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$How much does Mention cost?$q$, $q$Mention's entry-level Solo plan starts at around $49 per month, with Pro, ProPlus and custom Enterprise/Company tiers available as needs scale up.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Does Mention have a free trial?$q$, $q$Yes, Mention offers a 14-day free trial, though it does not currently offer a permanent free plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Where is Mention based?$q$, $q$Mention is headquartered in Paris, France, and was originally developed inside the eFounders startup studio.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$What sources does Mention monitor?$q$, $q$Mention monitors social networks such as Facebook, Instagram, X, TikTok, Reddit, Pinterest and YouTube, plus news sites, blogs, forums, and more than 75 review platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Is Mention suitable for agencies?$q$, $q$Yes, Mention offers white-label reporting and multi-client management features that are commonly used by PR and social media agencies.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Brand Reputation Monitoring$q$, $q$Marketing and communications teams track what customers and press are saying about their brand across social and news channels in real time.$q$, $q$In-house marketing and PR teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Agency Client Reporting$q$, $q$PR and social media agencies use Mention to monitor multiple client brands and generate white-labeled reports.$q$, $q$PR and social media agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Competitive Intelligence$q$, $q$Companies track competitor mentions and share of voice to benchmark campaign performance and market positioning.$q$, $q$Marketing strategists and brand managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Solo$q$, $q$$49/month$q$, $q$Monthly (lower with annual billing)$q$, NULL, $q$["1 user","2 alerts","Core social and web monitoring"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Pro$q$, $q$$99/month$q$, $q$Monthly$q$, NULL, $q$["10 users","5 alerts","Advanced analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$ProPlus$q$, $q$$179/month$q$, $q$Monthly$q$, NULL, $q$["More users and alerts","Additional integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$Company/Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Dedicated account manager","Custom onboarding","White-label reporting","API access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mention is a media monitoring and social listening tool that helps businesses, agencies and individuals keep track of what is being said about their brand, products, competitors or any topic of interest across the web. It was created in Paris in 2011-2012 inside the eFounders startup studio and has since grown into a platform used in over 125 countries.$q$, $q$The platform is built around 'alerts', which are saved Boolean search queries that continuously scan social networks, news sites, blogs, forums and review platforms for matching mentions, surfacing results in a real-time dashboard along with sentiment and volume analytics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mention monitors major social networks such as Facebook, Instagram, X, Reddit, TikTok, Pinterest and YouTube, general web content like news articles, blogs and forums, and more than 75 review sites including Google, Trustpilot, Amazon and Glassdoor. Boolean search operators let users build precise alerts to filter out noise.$q$, $q$On top of raw monitoring, Mention provides sentiment analysis, share-of-voice tracking, competitor benchmarking, influencer and author scoring, and customizable, white-labelable reporting dashboards, which makes it popular with PR and social media agencies managing multiple client brands.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('697e3318-d5de-4b30-adef-f66e599b0f6d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mention is sold on a subscription basis with tiers that scale by number of users, alerts and add-on features. The entry-level Solo plan is priced at roughly $49 per month for a single user and a small number of alerts, with lower effective pricing available on annual billing.$q$, $q$Higher tiers add more users, alerts, historical data access, integrations such as Slack and Zapier, and API access, while the top Company or Enterprise tier is custom-priced and includes a dedicated account manager; a 14-day free trial is generally available to test the platform.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Paige AI Local SEO Agent$q$, $q$An autonomous AI agent that continuously optimizes a Google Business Profile, including posts, Q&A, attributes and categories.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Automated Citation Building$q$, $q$Creates and syncs business citations across more than 60 online directories with minimal manual setup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Review Management$q$, $q$Monitors and helps manage Google reviews as part of ongoing profile optimization.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$White-Label Agency Tools$q$, $q$Agencies can white-label Paige and reporting for their own clients under the Agency Partner Program.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Sam Lead Generation$q$, $q$A free lead-generation tool that surfaces local businesses that may need SEO help, aimed at agencies.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Professional Management Services$q$, $q$Done-for-you Google Business Profile setup and ongoing management for businesses that prefer a managed service.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Multi-Location Support$q$, $q$Per-profile pricing structure supports businesses and agencies managing many locations or clients.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Automates much of the day-to-day work of Google Business Profile optimization$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Low-cost trial option lets businesses see results before committing to a full subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Dedicated agency program with discounted rates and white-label options$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Covers both self-service software and fully managed service tiers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Focused specifically on local and Google Maps SEO rather than broad general SEO$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Per-profile pricing can add up quickly for businesses or agencies managing many locations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Citation building and other add-ons carry additional monthly costs on top of the base Paige plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$As an AI-automated tool, results depend heavily on Google's frequently changing local ranking algorithm$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Less brand recognition than larger local SEO platforms such as Yext or SOCi$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Managed-service tier pricing requires a custom quote rather than transparent self-checkout$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$What does Merchynt do?$q$, $q$Merchynt provides AI-powered local SEO tools, most notably an AI agent called Paige, that optimize and manage Google Business Profile listings to improve Google Maps rankings.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$How much does Merchynt cost?$q$, $q$Merchynt's Paige AI plan is priced at $99 per month per Google Business Profile, with additional add-ons such as Citation Software priced separately.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Does Merchynt offer a free trial?$q$, $q$Yes, Merchynt offers a low-cost trial, sometimes as low as $1, so businesses can evaluate results before paying the full monthly price.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Is Merchynt built for agencies?$q$, $q$Yes, Merchynt runs a dedicated Agency Partner Program offering discounted pricing, white-label tools and a lead-generation tool called Sam for agencies managing multiple client locations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Where is Merchynt based?$q$, $q$Merchynt is headquartered in Santa Monica, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$What is Paige?$q$, $q$Paige is Merchynt's AI agent that autonomously manages and optimizes a business's Google Business Profile to improve local search and Google Maps visibility.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Small Business Local Ranking$q$, $q$A single-location business uses Paige to automatically optimize its Google Business Profile without hiring a dedicated SEO specialist.$q$, $q$Small and local businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Agency Client Management at Scale$q$, $q$SEO and marketing agencies use Merchynt's Agency Partner Program to manage local SEO for many client locations under white-labeled branding.$q$, $q$Local SEO and marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Multi-Location Citation Cleanup$q$, $q$Multi-location businesses use Merchynt's Citation Software to create and correct citations across dozens of online directories at once.$q$, $q$Multi-location businesses and franchises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Paige$q$, $q$$99/month per Google Business Profile$q$, $q$Monthly$q$, NULL, $q$["AI-driven profile optimization","Automated posts and Q&A management","Review monitoring","White-label option for agencies"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Citation Software$q$, $q$$40/month per profile ($20 for Agency Partners)$q$, $q$Monthly$q$, NULL, $q$["Citation creation across 60+ directories","Auto-sync with Google updates","Duplicate listing prevention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$Agency Partner Program$q$, $q$$100/month$q$, $q$Monthly$q$, NULL, $q$["Discounted Paige and Citation Software pricing","Free Sam lead tool access","Priority support","Sales and marketing materials"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Merchynt is a local SEO software company focused on helping small businesses and the agencies that serve them rank higher in Google Maps and local search results. Its main product, an AI agent called Paige, is designed to autonomously manage and optimize a business's Google Business Profile on an ongoing basis.$q$, $q$Founded around 2019 and based in Santa Monica, California, Merchynt has grown a product suite that spans AI-driven profile optimization, automated citation building, and professional local SEO management services, alongside a dedicated program for agencies that manage local SEO on behalf of clients.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Paige, Merchynt's flagship AI tool, continuously monitors a Google Business Profile and competitor listings, then automatically publishes posts, manages business information, tracks review trends and adjusts profile attributes to improve local ranking, aiming to replace much of the manual work of a local SEO specialist.$q$, $q$Merchynt's Citation Software automatically creates and keeps business citations synced across more than 60 online directories, while its Sam tool helps agencies generate new client leads. Together, these tools plus done-for-you management services give Merchynt both a self-service software offering and a managed-service option.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3b0618a9-c067-473b-869a-3d9864cb6eda', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Paige is priced at $99 per month per Google Business Profile, with a low-cost trial (as little as $1) available to preview results before paying full price. Citation Software costs an additional $40 per month per profile.$q$, $q$Agencies can join the Agency Partner Program for around $100 per month to get discounted rates on Paige and Citation Software, free access to the Sam lead-generation tool, and priority support, while businesses wanting fully managed services can instead purchase professional management packages typically priced from $125 to $400 per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Business Checking and Savings$q$, $q$Free business checking and savings accounts with no monthly account fees.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Corporate Credit Cards$q$, $q$Startup-friendly corporate credit cards integrated directly into the Mercury banking dashboard.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Invoicing and Bill Pay$q$, $q$Built-in invoicing, including recurring and API-driven invoicing on paid tiers, plus unlimited bill pay.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Expense Reimbursements$q$, $q$Manage employee expense reimbursements for a set number of active users per month, scaling with the paid plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Treasury and Idle Cash Management$q$, $q$Access to money-market funds and treasury tools to earn yield on excess operating cash.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Accounting Integrations$q$, $q$Free, automated syncing with QuickBooks and Xero to streamline bookkeeping.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$1099 Tax Filing$q$, $q$Basic 1099 filing included on the free plan, with unlimited filings on paid tiers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Free core banking account with no monthly fees or minimum balance requirements$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Modern, developer- and founder-friendly interface with strong startup ecosystem integrations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Backed by well-known venture investors and has raised substantial funding, suggesting financial stability$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Bundles banking, invoicing, treasury and credit into a single platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Popular and well-reviewed among the venture-backed startup community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Not a chartered bank itself, so accounts rely on partner-bank infrastructure that has changed over time$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Advanced features such as a dedicated relationship manager require the higher-cost Pro plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Primarily optimized for US-based startups, with more limited international support than some competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Fee-free ACH debit invoicing requires the Pro plan; Plus users pay per transaction$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$As with any fintech relying on partner banks, account changes tied to banking-partner transitions have occurred historically$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Is Mercury a bank?$q$, $q$No, Mercury is a financial technology company, not a chartered bank; banking services are provided through partner banks, with deposits eligible for FDIC insurance through those partners.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$How much does Mercury cost?$q$, $q$Mercury's core account is free, with optional Plus (about $29.90/month) and Pro (about $299/month) plans that add higher invoicing volumes and additional features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Who founded Mercury?$q$, $q$Mercury was founded in 2017 by Immad Akhund, Max Tagher and Jason Zhang in San Francisco.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Who is Mercury designed for?$q$, $q$Mercury is designed primarily for startups and scaling technology companies, though it also serves e-commerce and other digitally native small businesses.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Does Mercury offer credit cards?$q$, $q$Yes, Mercury offers corporate credit cards integrated into its banking dashboard alongside checking, savings and treasury products.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$How much funding has Mercury raised?$q$, $q$Mercury has raised several hundred million dollars in funding from investors including Sequoia Capital, Andreessen Horowitz and Coatue, and was valued at approximately $5.2 billion in a 2026 round.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Startup Banking and Runway Management$q$, $q$Venture-backed startups use Mercury as their primary bank account to manage runway, payroll funding and vendor payments.$q$, $q$Venture-backed technology startups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Startup Treasury Management$q$, $q$Companies with significant cash reserves use Mercury's treasury features to earn yield on idle operating cash via money-market fund access.$q$, $q$Well-funded startups and scale-ups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Small Business Invoicing and Bill Pay$q$, $q$Small digitally native businesses use Mercury's built-in invoicing and bill-pay tools to manage day-to-day finance operations without separate software.$q$, $q$Small and e-commerce businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Mercury (Free)$q$, $q$$0/month$q$, $q$N/A$q$, NULL, $q$["Business checking and savings","Unlimited bill pay","Basic invoicing","Reimbursements for up to 5 users/month","QuickBooks and Xero integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Mercury Plus$q$, $q$$29.90/month ($23.95/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Recurring invoicing","Invoicing API (500/month)","Reimbursements for up to 20 users/month","Unlimited 1099 filings"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$Mercury Pro$q$, $q$$299/month ($239.90/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Dedicated relationship manager","Free ACH debit invoicing","Unlimited invoicing API","NetSuite categorizations","Reimbursements for up to 250 users/month"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mercury is a financial technology company offering business banking built specifically for startups and growing companies. Founded in San Francisco in 2017 by Immad Akhund, Max Tagher and Jason Zhang, Mercury pairs a modern web and mobile banking interface with the account infrastructure of partner banks, since Mercury itself is not a chartered bank.$q$, $q$The platform has grown beyond checking and savings into a broader finance stack for startups, including corporate credit cards, treasury and money-market access for idle cash, venture debt facilitation, and accounting integrations, positioning itself as an alternative to traditional business banking at incumbent institutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mercury's free plan includes business checking and savings accounts, unlimited bill pay, basic invoicing, expense reimbursements for a handful of active users, and free accounting automations for QuickBooks and Xero, all with no monthly account fees.$q$, $q$Paid Plus and Pro tiers add features such as recurring and API-driven invoicing at higher volumes, more reimbursement seats, a dedicated relationship manager on the Pro tier, NetSuite categorization support, and unlimited 1099 tax filings, aimed at companies with more complex finance operations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83233571-dfd1-4aa8-9b81-a9cb76f036cd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mercury's base account is free, with business checking, savings, debit and credit card transactions and core banking features included at no monthly cost.$q$, $q$Two paid tiers extend the platform: Mercury Plus at roughly $29.90 per month (about $23.95 per month billed annually) and Mercury Pro at roughly $299 per month (about $239.90 billed annually), each unlocking higher invoicing volumes, more reimbursement seats and additional integrations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Unified Health Timeline$q$, $q$Aggregates records from multiple connected patient portals into a single chronological view.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$FHIR and SMART-on-FHIR Connectivity$q$, $q$Connects to healthcare providers using the standard HL7 FHIR patient-access API and SMART-on-FHIR authentication.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Lab Value Trending$q$, $q$Visualizes how specific lab results change over time across multiple visits and providers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Local-First, Offline Storage$q$, $q$Stores health records directly on the user's device rather than a centralized cloud server.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Zero-Knowledge Encryption$q$, $q$Supports client-side encryption so sensitive medical data remains under the user's exclusive control.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Cross-Provider Document Search$q$, $q$Lets users search across documents, notes and results from every connected provider at once.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Free and fully open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Aggregates records from multiple health systems without needing separate logins for each portal$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Local-first architecture keeps sensitive medical data on the user's own device$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Built on the standard FHIR/SMART-on-FHIR interoperability protocol rather than proprietary integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Listed in the official SMART Health IT app gallery, indicating standards compliance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Requires providers to support FHIR/SMART-on-FHIR patient-access APIs, which not every clinic offers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$As a small, independently maintained open-source project, it lacks dedicated commercial support or an SLA$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Self-hosting or local setup requires more technical comfort than a typical consumer health app$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Feature set is more limited than large commercial patient-portal aggregators backed by major tech companies$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Depends on continued volunteer maintenance since there is no company behind the project$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Is Mere Medical free?$q$, $q$Yes, Mere Medical is free and open source under the MIT license, with no subscription fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$How does Mere Medical connect to my medical records?$q$, $q$It uses the HL7 FHIR patient-access API with SMART-on-FHIR authentication, the interoperability standard supported by many US healthcare providers, to pull records directly from patient portals.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Where is my health data stored with Mere Medical?$q$, $q$Mere Medical is local-first and offline-first, storing records directly on the user's own device rather than a centralized cloud server, with support for zero-knowledge encryption.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Who maintains Mere Medical?$q$, $q$Mere Medical is an independent open-source project created and maintained by developer Chris Fu, with the source code publicly available on GitHub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Can Mere Medical connect to any hospital?$q$, $q$Only providers that support the FHIR patient-access standard with SMART-on-FHIR authentication can be connected, so coverage depends on each provider's own systems.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Is Mere Medical the same as Apple Health Records?$q$, $q$No, Mere Medical is an independent open-source project rather than a feature of a commercial operating system, though it serves a similar purpose of aggregating records from multiple providers using FHIR.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Chronic Condition Record Aggregation$q$, $q$Patients managing a chronic condition across several specialists use Mere to see all their labs and notes in one timeline.$q$, $q$Patients with complex or chronic health conditions$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Family Caregiving Coordination$q$, $q$Caregivers use Mere to consolidate records for a family member seen across multiple providers and health systems.$q$, $q$Family caregivers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Self-Hosted Personal Health Archive$q$, $q$Privacy-focused individuals self-host Mere to maintain a personal, offline-first archive of their full medical history.$q$, $q$Privacy-conscious individuals and self-hosting enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT-licensed source code","FHIR/SMART-on-FHIR connectivity","Local-first storage","Zero-knowledge encryption support","Community support via GitHub"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mere Medical is an open-source personal health record application that lets individuals pull together medical records scattered across multiple hospital and clinic patient portals into one unified, searchable timeline. It is built and maintained by an independent developer and distributed freely under the MIT license.$q$, $q$The app connects to healthcare providers using the HL7 FHIR patient-access standard with SMART-on-FHIR authentication, the same interoperability standard many US health systems support due to federal patient-data-access regulations, meaning users do not need proprietary integrations from each hospital to consolidate their records.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Once connected to a patient portal, Mere pulls in labs, immunizations, medications, clinical notes and visit summaries, then presents them as a single chronological timeline that spans every connected provider, along with consolidated views like a full immunization history and lab-value trending across visits.$q$, $q$The application is offline-first and local-first, storing records directly on the user's device rather than a centralized server, and supports zero-knowledge client-side encryption, giving users full control over their sensitive health data even in self-hosted deployments.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mere Medical is free and open source under the MIT license, with the source code publicly available on GitHub and no company operating it as a paid SaaS product.$q$, $q$Because the app can be run locally or self-hosted, the only potential cost is whatever infrastructure a user chooses for self-hosting; there are no subscription fees, premium tiers, or per-record charges built into the software itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1a73a78a-9eb5-44c7-beb9-2f36900d5602', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Cardless Corporate Cards$q$, $q$Instantly provisions virtual and physical corporate cards without the delays of traditional card issuance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Rule-Based Spend Controls$q$, $q$Sets granular limits by vendor, category or employee to prevent out-of-policy spend before it happens.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Automated Expense Reconciliation$q$, $q$Automatically matches transactions with receipts and accounting codes to cut down on manual expense reports.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Real-Time Spend Dashboards$q$, $q$Gives finance teams live visibility into company spend rather than waiting for end-of-month statements.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Travel and Expense Management$q$, $q$Combines travel booking and related spend management with everyday corporate card controls in one platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Cashback Rewards$q$, $q$Offers cashback on card transactions across all pricing tiers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Vendor and Subscription Management$q$, $q$Helps track and control recurring vendor and SaaS subscription spend.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Free tier available for small teams, unlike many corporate card competitors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Cardless issuance lets teams provision cards instantly rather than waiting for physical delivery$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Combines spend management and travel and expense in a single platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Real-time visibility into spend helps finance teams catch issues before month-end$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Backed by well-known investors, suggesting financial stability at scale$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Free tier is capped at just three users, so most growing teams will need a paid plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Premium tier pricing is per-user, which can add up for larger organizations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Enterprise pricing is custom and not published, requiring a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Smaller market presence and brand recognition compared to larger competitors like Brex or Ramp$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Some advanced spend-control and reporting features are reserved for higher-priced tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$What does Mesh Payments do?$q$, $q$Mesh Payments is a corporate spend management platform offering cardless corporate cards, automated expense management and travel and expense controls for businesses.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Is Mesh Payments free?$q$, $q$Mesh offers a free Pro tier for companies with up to three users, with a Premium tier at roughly $13 per user per month and custom Enterprise pricing for larger organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Who founded Mesh Payments?$q$, $q$Mesh Payments was founded in 2018 by Eran Katoni and Oded Zehavi.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Where is Mesh Payments headquartered?$q$, $q$Mesh Payments is headquartered in New York.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$How much funding has Mesh Payments raised?$q$, $q$Mesh Payments has raised approximately $123 million in total funding from investors including Tiger Global Management, TLV Partners and Alpha Wave Global.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Does Mesh Payments offer travel management?$q$, $q$Yes, Mesh includes dedicated travel and expense (T&E) management functionality alongside its core corporate card and spend management features.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Startup Spend Control$q$, $q$Growing startups use Mesh's free or Premium tier to issue cardless corporate cards and enforce spend rules without manual expense reports.$q$, $q$Venture-backed startups and small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Distributed Team Expense Management$q$, $q$Companies with remote or distributed employees use Mesh to instantly issue cards and monitor spend in real time across locations.$q$, $q$Mid-market companies with distributed teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Corporate Travel and Expense Consolidation$q$, $q$Finance teams use Mesh to manage travel bookings and related spend alongside everyday card transactions in a single system.$q$, $q$Finance and operations teams managing corporate travel$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Pro$q$, $q$Free (up to 3 users)$q$, $q$N/A$q$, NULL, $q$["Unlimited cards","Cashback rewards","No long-term commitment","Core spend management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Premium$q$, $q$$13/user/month$q$, $q$Monthly$q$, NULL, $q$["Advanced spend controls","Enhanced reporting","Scales with global growth"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Complete spend and travel control","Custom workflows","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mesh Payments is a corporate spend management platform that gives businesses virtual and physical corporate cards alongside automated expense management and travel and expense (T&E) controls. It was founded in 2018 by Eran Katoni and Oded Zehavi and is headquartered in New York.$q$, $q$The platform is designed to give finance teams real-time visibility into company spend as it happens, replacing the reconciliation-after-the-fact model of traditional corporate cards and manual expense reports with rule-based controls and automated categorization.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mesh issues cardless and physical corporate cards that can be provisioned instantly and governed by granular spend rules set per vendor, category or employee, giving finance teams control over spend before it happens rather than after.$q$, $q$The platform automatically reconciles transactions with receipts and accounting codes, reducing manual expense-report work, and includes dedicated travel and expense management functionality alongside real-time dashboards and cashback on card spend.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('13a40e93-2361-4019-8f00-7522e0ed8bb9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mesh uses a freemium pricing model: its Pro tier is free for companies with up to three users, including unlimited cards and cashback with no long-term commitment.$q$, $q$Companies that need more advanced spend-control and reporting features can upgrade to the Premium tier at roughly $13 per user per month, while large organizations with complex global spend and travel requirements can get custom Enterprise pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$No-Code Visual Query Builder$q$, $q$Lets non-technical users explore data and build charts without writing SQL.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Native SQL Editor$q$, $q$Gives analysts and engineers a full SQL editor for more advanced or custom queries.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Interactive Dashboards$q$, $q$Combines multiple charts and questions into shareable, interactive dashboards.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Embedded Analytics$q$, $q$Lets companies embed Metabase dashboards and charts directly into their own customer-facing products.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Scheduled Alerts$q$, $q$Sends automated email or Slack alerts when data crosses defined thresholds.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$X-Ray Automated Exploration$q$, $q$Automatically generates summary insights and visualizations about a dataset with one click.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Broad Database Support$q$, $q$Connects to major relational databases and data warehouses including PostgreSQL, MySQL, Snowflake, BigQuery and Redshift.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Role-Based Permissions$q$, $q$Governs which users and groups can view or query specific data, available in more depth on paid tiers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Free, genuinely open-source edition with unlimited users and no artificial feature caps on core functionality$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Easy to install and self-host, running from a single JAR file or Docker container$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Accessible no-code interface makes it usable by non-technical business users, not just analysts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Broad support for popular databases and data warehouses out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Large, active open-source community with strong GitHub presence and frequent releases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Enterprise features such as SSO, SCIM and audit logs require a paid Pro or Enterprise plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Self-hosted deployments require the user to manage servers, upgrades and backups$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Cloud Starter and Pro plans can get expensive quickly as user counts grow beyond included seats$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Less advanced modeling and governance tooling than large enterprise BI suites like Looker or Tableau$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Enterprise tier pricing is not fully transparent and requires a custom quote$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Is Metabase free?$q$, $q$Yes, Metabase's Open Source edition is free to self-host with unlimited users; paid Cloud and Enterprise tiers add managed hosting, SSO and advanced governance features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Who created Metabase?$q$, $q$Metabase was started in 2014 by Sameer Al-Sakran along with co-founders including Allen Gilliland, originally as a side project at the Expa startup studio in San Francisco.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Does Metabase require SQL knowledge?$q$, $q$No, Metabase includes a no-code visual query builder for non-technical users, alongside a native SQL editor for analysts who prefer to write queries directly.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$What databases does Metabase support?$q$, $q$Metabase connects to major relational databases and data warehouses including PostgreSQL, MySQL, Snowflake, BigQuery and Redshift, among others.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$How much does Metabase Cloud cost?$q$, $q$Metabase Cloud Starter is priced at roughly $500 per month including 10 users, with Pro plans at roughly $575 per month and custom Enterprise pricing above that.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Can Metabase be embedded in another product?$q$, $q$Yes, Metabase supports embedded analytics, letting companies embed dashboards and charts directly into their own customer-facing applications.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Internal Company Analytics$q$, $q$Startups and small data teams self-host the free Open Source edition to give employees self-service dashboards and reporting.$q$, $q$Startups and small data teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Embedded Customer-Facing Analytics$q$, $q$SaaS companies use Metabase's embedding features to build analytics dashboards directly into their own product for customers.$q$, $q$SaaS product and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Enterprise Governed Reporting$q$, $q$Larger organizations use Metabase Cloud or Enterprise for managed hosting, SSO and permission-governed reporting across departments.$q$, $q$Mid-market and enterprise data teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted deployment","Unlimited users","Core dashboards and SQL editor","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Cloud Starter$q$, $q$$500/month (10 users included)$q$, $q$Monthly or annual$q$, NULL, $q$["Fully managed cloud hosting","10 included users, $10/extra user/month","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Cloud Pro$q$, $q$$575/month (10 users included)$q$, $q$Monthly or annual$q$, NULL, $q$["SSO (SAML, LDAP, JWT)","SCIM user provisioning","Advanced embedding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$Enterprise$q$, $q$From $20,000/year$q$, $q$Annual$q$, NULL, $q$["Audit logs","Advanced permissions","Dedicated support","Custom deployment options"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Metabase is an open-source business intelligence and analytics platform designed to let both technical and non-technical users ask questions of their data and build dashboards without necessarily writing SQL. It began in 2014 as a side project by Sameer Al-Sakran and co-founders at the Expa startup studio in San Francisco, growing through developer word-of-mouth on GitHub before becoming a funded company.$q$, $q$The company has raised funding from NEA and Insight Partners across seed, Series A and Series B rounds, grown to over 100 employees, and now offers Metabase both as free self-hosted open-source software and as a fully managed Metabase Cloud service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Metabase connects to popular relational databases and data warehouses such as PostgreSQL, MySQL, Snowflake, BigQuery and Redshift, and provides both a no-code visual query builder for business users and a native SQL editor for analysts, letting one tool serve mixed-skill teams.$q$, $q$The platform includes interactive dashboards, scheduled alerts delivered by email or Slack, embedded analytics for building customer-facing reporting into other products, and an automated 'X-ray' exploration feature that surfaces summary insights about a dataset without manual query-writing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('742ef257-e98d-45ec-870b-b12953892eab', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Metabase's Open Source edition is completely free to self-host, with unlimited users and community support, making it a popular starting point for startups and small data teams.$q$, $q$For teams wanting managed hosting or enterprise features like SSO and audit logs, Metabase Cloud Starter is priced at roughly $500 per month for 10 users, Cloud Pro at roughly $575 per month, and Enterprise pricing starts around $20,000 per year for the largest deployments.$q$]::text[], 2);
