-- Enrichment marathon batch: Memos, Mend.io, Mention, Merchynt, Mercury, Mere Medical, Mesh Payments, Metabase

-- ── Memos ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Memos is an open-source, self-hosted, Markdown-native note-taking app built for quick, lightweight capture of notes, ideas and daily logs.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$, $q$Japanese$q$, $q$Korean$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Memos Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Memos review: an open-source, self-hosted Markdown note-taking app. See features, deployment options, free pricing, and top alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Memos (usememos) is an open-source, self-hosted note-taking application designed for fast, low-friction capture of short notes, ideas, links and daily logs. The project is developed by the usememos organization on GitHub, with its first public releases appearing in 2022. Memos is released under the MIT license, meaning it is free to use, modify and self-host with no subscription fees, per-seat charges or vendor lock-in. The backend is written in Go and compiles to a single lightweight binary, distributed as a roughly 20MB Docker image that can run on a Raspberry Pi, a VPS, or any cloud server. It supports SQLite, MySQL or PostgreSQL as its data store, giving users flexibility from a single-user hobby deployment up to larger self-hosted team instances. Architecturally, Memos exposes both REST and gRPC APIs, which lets developers build integrations, browser extensions, or mobile clients on top of the core note store. The frontend is a progressive web app with offline support, dark mode, and a timeline-based interface that resembles a personal microblog rather than a traditional folder-based notes app. Core features include Markdown-native editing with syntax highlighting, table support and LaTeX math rendering, drag-and-drop attachments for images, video, audio and documents, full-text search, a flexible tagging system for organizing notes, and one-click export to Markdown, JSON or CSV so notes always remain portable. Users can selectively share individual memos via public links while keeping the rest of their notes private, and the zero-telemetry design means no usage data is sent to any third party. Because Memos is entirely self-hosted, target users are privacy-conscious individuals, developers, and small teams who want a lightweight alternative to cloud note services like Notion, Evernote or Google Keep without recurring costs or data-ownership concerns. Its closest open-source competitors include Trilium Notes, Joplin, Anytype and Flatnotes, while on the commercial side it is often compared to Notion and Obsidian. Memos differentiates itself through its extreme simplicity: it deliberately avoids the complex nested-page hierarchies of Notion in favor of a flat, tag-driven, timeline-first workflow optimized for quick daily capture rather than long-form document authoring. Deployment simplicity is another differentiator, since a single Docker command is typically enough to get a working instance running, and the project maintains an active GitHub community that contributes translations, themes and client integrations. Because there is no vendor and no company behind Memos in the traditional SaaS sense, pricing is not applicable beyond the cost of the server or hosting the user chooses to run it on.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4d5b94dc-fbd1-4f00-aeaf-079f4a300745';

