-- ── Mention ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mention is a real-time social listening and media monitoring platform that tracks brand, competitor and industry mentions across social media, news, blogs, forums and review sites.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$49/month (Solo plan, billed monthly)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$, $q$Portuguese$q$, $q$Italian$q$]::text[],
  seo_title = COALESCE($q$Mention Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mention review: real-time social listening and media monitoring across social, news and review sites. See features, pricing plans and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mention is a social listening and media monitoring platform that lets brands, agencies and individuals track mentions of their name, products, competitors or any keyword across social media, news sites, blogs, forums, videos, images and review platforms in real time. The product originated in November 2011 inside eFounders (now Hexa), a Paris-based startup studio, where developer Arnaud Le Blanc wrote the first version alongside Edouard de la Joncquiere; the two officially co-founded the company in 2013, and Mention is generally described as having launched commercially in 2012. Matthieu Vaxelaire, previously a partner at eFounders, became Mention's CEO in October 2014 and led the company through a period of rapid growth, reportedly reaching hundreds of thousands of users within a few years of launch. Mention remains headquartered in Paris, France, and has grown to serve customers across more than 125 countries. Architecturally, Mention operates as a cloud-based SaaS platform that continuously crawls and indexes web and social content, using Boolean search logic (AND, OR, NOT, wildcards) to let users build precise monitoring queries called 'alerts.' It covers major social networks including Facebook, Instagram, X (formerly Twitter), Reddit, TikTok, Pinterest and YouTube, general web sources such as news outlets, blogs and forums, and more than 75 review sites including Google, Trustpilot, Amazon and Glassdoor. On top of raw monitoring, Mention layers analytics such as sentiment analysis, share-of-voice and competitor benchmarking, influence scoring to identify high-impact authors, and customizable reporting dashboards that can be white-labeled for agency use. Pricing is subscription-based with tiers historically named Solo, Pro, ProPlus and Company/Enterprise; the entry Solo plan has been priced around $49 per month with one to two alerts and a single user, scaling up through higher-volume plans with more users, alerts and add-ons such as historical data access, Slack and Zapier integrations, and API access, up to custom Enterprise pricing with dedicated account management. A 14-day free trial is typically available, though Mention has at various points discontinued a permanent free tier. Mention's target audience spans marketing and communications teams at small and mid-sized businesses, PR and social media agencies managing multiple client brands, and enterprise brand-management teams needing to track reputation and campaign performance across many markets and languages. Its principal competitors include Brandwatch, Sprout Social, Meltwater, Talkwalker, Awario, Brand24 and Mentionlytics. Mention differentiates itself with an accessible, mid-market price point relative to enterprise-grade tools like Brandwatch or Meltwater, combined with broad source coverage and an agency-friendly white-label reporting feature, positioning it between lightweight free mention trackers and expensive enterprise social intelligence suites.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '697e3318-d5de-4b30-adef-f66e599b0f6d';

