-- ── Mercury ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mercury is a fintech platform that provides business banking, including checking, savings, credit cards and treasury tools, built primarily for startups and scaling companies.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $29.90/month)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mercury Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mercury review: startup-focused business banking with checking, savings, credit cards and treasury tools. See features, pricing plans and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mercury is a financial technology company that provides banking services designed specifically for startups and scaling businesses. It was founded in 2017 in San Francisco by Immad Akhund, Max Tagher and Jason Zhang; Akhund, the CEO, had previously sold his mobile advertising startup for $45 million in 2016, while Tagher and Zhang had worked with him previously. Mercury is a fintech, not a chartered bank itself: banking services are provided through partner banks, with deposits eligible for FDIC insurance through those partner banks and sweep networks. The company has raised several hundred million dollars in primary and secondary funding across multiple rounds from investors including Sequoia Capital, Andreessen Horowitz, Coatue, CRV and Spark Capital, reaching a reported valuation of about $5.2 billion as of a 2026 funding round. Mercury's core product is a free business checking and savings account with no monthly fees, accessed through a web and mobile banking dashboard, and includes features such as bill pay, basic invoicing, expense reimbursements, and free accounting integrations with QuickBooks and Xero. Beyond the free tier, Mercury offers two paid plans, Mercury Plus at roughly $29.90 per month and Mercury Pro at roughly $299 per month (with discounts for annual billing), which unlock additional invoicing volume, more reimbursement seats, a dedicated relationship manager, NetSuite integration and unlimited 1099 tax filing support. Mercury has also expanded into corporate credit cards, venture debt facilitation, treasury and money-market fund access for idle cash, and AI-assisted tools for founders. The target audience is primarily venture-backed and bootstrapped technology startups, along with e-commerce and other digitally native small businesses that want a modern, API-friendly banking experience without the friction of traditional business banking at incumbent banks. Mercury's main competitors include Brex, Ramp, Rho, Novo, Relay and the business-banking divisions of traditional banks. Mercury differentiates itself through a startup-native product experience, deep integrations with startup tooling, and a design-forward interface, while positioning itself as a comprehensive finance stack rather than a single banking product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '83233571-dfd1-4aa8-9b81-a9cb76f036cd';

