-- ── Mere Medical ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mere Medical is an open-source, offline-first personal health record app that aggregates and syncs medical records from multiple patient portals using FHIR standards.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mere Medical Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mere Medical review: an open-source, self-hosted personal health record app that aggregates records from patient portals via FHIR. Features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mere Medical is an open-source, self-hostable personal health record (PHR) application built to aggregate a person's medical records from multiple patient portals into a single, unified timeline. The project is created and maintained by developer Chris Fu (GitHub handle cfu288) and is distributed under the MIT license, with its source code publicly available on GitHub. Rather than requiring users to log into each hospital's or clinic's separate patient portal individually, Mere connects to healthcare providers' systems using HL7 FHIR (Fast Healthcare Interoperability Resources) patient-access APIs, authenticated through SMART-on-FHIR, the widely adopted standard that many US hospital systems support as a result of federal interoperability regulations. Once connected, Mere pulls in clinical data such as lab results, immunizations, medications, clinical notes and visit summaries, and normalizes them into a single, searchable, chronological health timeline that spans every connected provider. Architecturally, the application is described as offline-first and local-first: records are stored directly on the user's own device rather than a centralized cloud server, and the project supports client-side, zero-knowledge encryption so that even self-hosted deployments keep sensitive health data under the user's exclusive control. Mere is listed in the SMART Health IT App Gallery, the official directory of apps built on the SMART-on-FHIR standard, and the project has been presented in an academic context at the American Medical Informatics Association (AMIA) symposium as an example of an open-source approach to patient-centered health record aggregation. Core features include a unified health timeline across all connected providers, consolidated summary views such as an aggregated immunization history, cross-provider document and lab search, laboratory value trending over time to visualize how specific test results change across multiple visits and providers, and access to clinical and provider notes where available through the FHIR API. Because it is open source and self-hosted (or run locally as a personal web app), Mere Medical carries no license fee and no company operates it as a commercial SaaS product; there is no vendor lock-in, subscription, or centralized data broker involved. The target users are privacy-conscious patients managing chronic conditions across multiple health systems, caregivers coordinating care for family members seen by different providers, and developers or researchers interested in patient-facing FHIR tooling. Its closest comparisons are other personal health record and patient-data-aggregation tools such as Apple Health Records and CommonHealth, but Mere differentiates itself by being fully open source, self-hostable, and architected around local-first, zero-knowledge-encrypted storage rather than a centralized company-run cloud service, giving users complete control over where their medical data lives.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1a73a78a-9eb5-44c7-beb9-2f36900d5602';

