-- ── Metabase ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Metabase is an open-source business intelligence platform that lets teams explore data, build dashboards and share insights without needing to write SQL.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (Open Source); Cloud Starter from $500/month$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Roughly 120-126 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Spanish$q$, $q$German$q$, $q$Japanese$q$, $q$Chinese$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Metabase Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Metabase review: open-source BI and analytics platform with dashboards, SQL and no-code querying. See features, self-hosted vs cloud pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Metabase is an open-source business intelligence and analytics platform that lets both technical and non-technical users explore data, build charts and dashboards, and share insights, without necessarily needing to write SQL. The project began in 2014 as a side project by Sameer Al-Sakran, together with co-founders including Allen Gilliland and Caspar Strickland, while Al-Sakran was working out of Expa, a San Francisco startup studio; Al-Sakran had previously run a startup called Settle and was motivated by the friction he had experienced getting straightforward answers out of company databases. The team open-sourced an early, AGPL-licensed Java application with a visual query builder that let non-technical users connect to a database and build charts within minutes, and the tool spread largely through GitHub and developer word of mouth rather than paid marketing. Metabase Inc. raised a roughly $2 million seed round led by NEA to polish the user experience and installation flow, followed by an $8 million Series A also led by NEA in 2019, and a $30 million Series B led by Insight Partners in August 2021, funding that helped grow the company to more than 100 employees and build out enterprise sales and customer-success functions; as of 2026 the company employs roughly 120 to 126 people and is headquartered in San Francisco. Architecturally, Metabase connects to relational databases and data warehouses (PostgreSQL, MySQL, Snowflake, BigQuery, Redshift and others), and offers a no-code visual query builder alongside a native SQL editor for more advanced users, letting a single tool serve both business users asking simple questions and analysts writing complex queries. Core features include interactive dashboards, scheduled email and Slack alerts, embedded analytics for building customer-facing reporting into other products, X-ray automated data exploration that surfaces summary insights automatically, and role-based permissions for governing who can see which data. Metabase is distributed in two license tracks: a free, permissively licensed Open Source edition (self-hosted, unlimited users, community support) and a commercial Enterprise/Pro edition adding SSO, SCIM provisioning, audit logs, advanced permissions and official support. It is also offered as a fully managed Metabase Cloud service, with Starter plans reported at roughly $500 per month including 10 users (plus per-additional-user fees), Pro plans at roughly $575 per month, and custom Enterprise pricing starting around $20,000 per year for the largest deployments. Metabase's target customers range from startups and small data teams self-hosting the free edition to run internal analytics, up to larger companies that pay for Metabase Cloud or Enterprise to get managed hosting, SSO and embedded analytics for customer-facing dashboards. Its main competitors include Looker (Google Cloud), Tableau (Salesforce), Power BI (Microsoft), Apache Superset, Redash and Preset. Metabase differentiates itself through its combination of genuine open-source availability, ease of installation, and a no-code interface accessible to non-technical users, positioning it as a lighter-weight, faster-to-deploy alternative to enterprise BI suites like Tableau or Looker.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '742ef257-e98d-45ec-870b-b12953892eab';

